-- ============================================================
-- STEP 0: Enable required extensions
-- Run this block first. pg_cron requires a Pro/paid plan.
-- If pg_cron fails on the free tier, comment it out — the
-- app will work without scheduled jobs.
-- ============================================================
CREATE EXTENSION IF NOT EXISTS "uuid-ossp" WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pg_net WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS supabase_vault WITH SCHEMA vault;
CREATE EXTENSION IF NOT EXISTS pgmq;
DO $$
BEGIN
  CREATE EXTENSION IF NOT EXISTS pg_cron WITH SCHEMA pg_catalog;
EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE 'pg_cron unavailable (free plan?) — skipping: %', SQLERRM;
END;
$$;

