  has_role(auth.uid(), 'admin'::app_role) OR
  has_role(auth.uid(), 'operations'::app_role) OR
  has_role(auth.uid(), 'dispatcher'::app_role) OR
  has_role(auth.uid(), 'driver'::app_role) OR
