ON public.financial_audit_log FOR INSERT TO authenticated
WITH CHECK (
  -- Only roles that can modify financial records can insert audit logs
  has_role(auth.uid(), 'admin'::app_role) OR
  has_role(auth.uid(), 'operations'::app_role) OR
  changed_by = auth.uid()
);


