  FOR SELECT USING (
    EXISTS (
      SELECT 1 FROM public.user_roles ur 
      WHERE ur.user_id = auth.uid() 
      AND ur.role IN ('ops_manager', 'org_admin', 'super_admin', 'admin', 'dispatcher')
    )
  );

