-- =====================================================
-- FUNCTIONS & TRIGGERS
-- =====================================================

-- Function to get user's organization
CREATE OR REPLACE FUNCTION public.get_user_organization(p_user_id UUID)
RETURNS UUID
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
    SELECT organization_id 
    FROM public.organization_members 
    WHERE user_id = p_user_id AND is_active = true
    LIMIT 1;
$$;

-- Function to check if user is org owner
CREATE OR REPLACE FUNCTION public.is_org_owner(p_user_id UUID, p_org_id UUID)
RETURNS BOOLEAN
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
    SELECT EXISTS (
        SELECT 1 FROM public.organization_members
        WHERE user_id = p_user_id 
        AND organization_id = p_org_id
        AND is_owner = true
        AND is_active = true
    );
$$;

-- Function to calculate RouteAce commission (20%)
CREATE OR REPLACE FUNCTION public.calculate_commission(
    p_gross_amount DECIMAL,
    p_reseller_rate DECIMAL DEFAULT 80.00
)
RETURNS TABLE(reseller_amount DECIMAL, routeace_amount DECIMAL)
LANGUAGE plpgsql
STABLE
AS $$
BEGIN
    RETURN QUERY SELECT 
        ROUND(p_gross_amount * (p_reseller_rate / 100), 2) as reseller_amount,
        ROUND(p_gross_amount * ((100 - p_reseller_rate) / 100), 2) as routeace_amount;
END;
$$;

-- Trigger to update updated_at
CREATE OR REPLACE FUNCTION public.update_organization_timestamp()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS update_organizations_timestamp ON public.organizations;
CREATE TRIGGER update_organizations_timestamp
    BEFORE UPDATE ON public.organizations
    FOR EACH ROW
    EXECUTE FUNCTION public.update_organization_timestamp();

DROP TRIGGER IF EXISTS update_organization_members_timestamp ON public.organization_members;
CREATE TRIGGER update_organization_members_timestamp
    BEFORE UPDATE ON public.organization_members
    FOR EACH ROW
    EXECUTE FUNCTION public.update_organization_timestamp();

DROP TRIGGER IF EXISTS update_reseller_relationships_timestamp ON public.reseller_relationships;
CREATE TRIGGER update_reseller_relationships_timestamp
    BEFORE UPDATE ON public.reseller_relationships
    FOR EACH ROW
    EXECUTE FUNCTION public.update_organization_timestamp();


-- ============================================================
-- FILE: 20260208190741_0c641c8c-db6f-48fa-b60f-c5f91eee7520.sql
-- ============================================================
-- Add ETA and KPI fields to dispatches table
ALTER TABLE public.dispatches 
ADD COLUMN IF NOT EXISTS estimated_delivery_days NUMERIC,
ADD COLUMN IF NOT EXISTS estimated_start_date DATE,
ADD COLUMN IF NOT EXISTS estimated_completion_date DATE,
ADD COLUMN IF NOT EXISTS total_drops INTEGER DEFAULT 1,
ADD COLUMN IF NOT EXISTS avg_wait_time_per_drop NUMERIC DEFAULT 2,
ADD COLUMN IF NOT EXISTS actual_delivery_days NUMERIC,
ADD COLUMN IF NOT EXISTS on_time_flag BOOLEAN,
ADD COLUMN IF NOT EXISTS dispatch_date DATE;

-- Create a function to auto-calculate on-time status when dispatch is delivered
CREATE OR REPLACE FUNCTION public.calculate_on_time_delivery()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $function$
BEGIN
  -- Only trigger when status changes to delivered
  IF NEW.status IN ('delivered', 'closed') AND OLD.status NOT IN ('delivered', 'closed') THEN
    -- Calculate actual delivery days if we have the dates
    IF NEW.actual_delivery IS NOT NULL AND NEW.dispatch_date IS NOT NULL THEN
      NEW.actual_delivery_days := EXTRACT(EPOCH FROM (NEW.actual_delivery - (NEW.dispatch_date::timestamp + interval '8 hours'))) / 86400;
      
      -- Determine on-time status
      IF NEW.estimated_delivery_days IS NOT NULL THEN
        NEW.on_time_flag := NEW.actual_delivery_days <= NEW.estimated_delivery_days;
      END IF;
    ELSIF NEW.actual_delivery IS NOT NULL AND NEW.scheduled_pickup IS NOT NULL THEN
      -- Fallback: use scheduled_pickup as start
      NEW.actual_delivery_days := EXTRACT(EPOCH FROM (NEW.actual_delivery - NEW.scheduled_pickup)) / 86400;
      
      IF NEW.estimated_delivery_days IS NOT NULL THEN
        NEW.on_time_flag := NEW.actual_delivery_days <= NEW.estimated_delivery_days;
      END IF;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$function$;

-- Create trigger for on-time delivery calculation
DROP TRIGGER IF EXISTS trigger_calculate_on_time_delivery ON public.dispatches;
CREATE TRIGGER trigger_calculate_on_time_delivery
  BEFORE UPDATE ON public.dispatches
  FOR EACH ROW
  EXECUTE FUNCTION public.calculate_on_time_delivery();

