  fx_exposure_percent NUMERIC(10,4) DEFAULT 0,
  revenue_concentration_ratio NUMERIC(10,4) DEFAULT 0,
  default_probability_percent NUMERIC(10,4) DEFAULT 0,
  cash_runway_months NUMERIC(10,2) DEFAULT 0,
