CREATE POLICY "Staff manage schedules" ON public.maintenance_schedules FOR ALL TO authenticated
  USING (has_role(auth.uid(),'admin') OR has_role(auth.uid(),'super_admin') OR has_role(auth.uid(),'ops_manager'))
