CREATE OR REPLACE FUNCTION public.sync_pod_to_outbound()
RETURNS TRIGGER LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  IF (NEW.pod_photo_url IS NOT NULL)
     AND (OLD.pod_photo_url IS DISTINCT FROM NEW.pod_photo_url) THEN
    UPDATE public.outbound_requests o
       SET pod_uploaded_url = NEW.pod_photo_url,
           pod_uploaded_at  = COALESCE(NEW.pod_uploaded_at, now()),
           pod_status       = 'uploaded'
      FROM public.dispatches d
     WHERE d.id = NEW.dispatch_id
       AND o.id = ANY(COALESCE(d.source_outbound_ids, ARRAY[]::UUID[]));
  END IF;
  RETURN NEW;
END $$;

DROP TRIGGER IF EXISTS trg_sync_pod_to_outbound ON public.ld_transporter_jobs;
CREATE TRIGGER trg_sync_pod_to_outbound
  AFTER UPDATE ON public.ld_transporter_jobs
  FOR EACH ROW EXECUTE FUNCTION public.sync_pod_to_outbound();



-- ============================================================
-- FILE: 20260507090022_4f208ed4-82fc-45d6-ab61-da9dfe5fbfaa.sql
-- ============================================================
-- Extend the transporterâ†’dispatch sync trigger to mirror accepted and in_transit
-- statuses, so the LD Tracking page, In-Transit Monitor, and Sales & Distribution
-- Tracker reflect transporter activity in real time.

CREATE OR REPLACE FUNCTION public.sync_transporter_pod_to_dispatch()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $function$
BEGIN
  -- POD uploaded â†’ delivered + POD photo on dispatch
  IF NEW.status = 'pod_uploaded' AND NEW.pod_photo_url IS NOT NULL THEN
    UPDATE public.dispatches
    SET
      pod_confirmed     = true,
      pod_photo_url     = NEW.pod_photo_url,
      pod_notes         = NEW.pod_notes,
      pod_confirmed_at  = NEW.pod_uploaded_at,
      status            = 'delivered',
      actual_delivery   = COALESCE(actual_delivery, NEW.delivered_at, now()),
      updated_at        = now()
    WHERE id = NEW.dispatch_id;
  END IF;

  -- Pickup confirmed â†’ picked_up
  IF NEW.status = 'pickup_confirmed' AND (OLD.status IS DISTINCT FROM 'pickup_confirmed') THEN
    UPDATE public.dispatches
    SET
      status        = 'picked_up',
      actual_pickup = COALESCE(actual_pickup, NEW.pickup_confirmed_at, now()),
      updated_at    = now()
    WHERE id = NEW.dispatch_id;
  END IF;

  -- In transit â†’ in_transit on dispatch (powers In-Transit Monitor + Sales KPIs)
  IF NEW.status = 'in_transit' AND (OLD.status IS DISTINCT FROM 'in_transit') THEN
    UPDATE public.dispatches
    SET
      status     = 'in_transit',
      updated_at = now()
    WHERE id = NEW.dispatch_id
      AND status NOT IN ('delivered','closed','cancelled');
  END IF;

  -- Accepted â†’ dispatched (job acknowledged, leaves "draft/pending")
  IF NEW.status = 'accepted' AND (OLD.status IS DISTINCT FROM 'accepted') THEN
    UPDATE public.dispatches
    SET
      status     = CASE WHEN status IN ('pending','draft','assigned') THEN 'dispatched' ELSE status END,
      updated_at = now()
    WHERE id = NEW.dispatch_id;
  END IF;

  RETURN NEW;
END;
$function$;


