    OR public.has_role(auth.uid(),'org_admin') OR public.has_role(auth.uid(),'ops_manager')
  ));

CREATE INDEX IF NOT EXISTS idx_fuel_logs_org_date ON public.fuel_logs(organization_id, log_date DESC);
