    AND lower(COALESCE(_metadata->>'mimetype', '')) IN ('image/jpeg', 'image/png', 'image/webp', 'image/gif')
    AND lower(COALESCE(storage.extension(_name), '')) IN ('jpg', 'jpeg', 'png', 'webp', 'gif')
$$;

